const express = require('express');
const winston = require('winston');
const morgan = require('morgan');

const app = express();

// Set up request logging with Morgan and Winston
app.use(morgan('combined', { stream: winston.stream }));

// Set up user-provided data logging
app.use((req, res, next) => {
  const logData = {
    username: req.user ? req.user.username : null,
    ipAddress: req.ip,
    customHeaders: req.headers,
  };
  winston.info(logData);
  next();
});

// Accept user input and write it directly to log files
app.post('/write-to-log', (req, res) => {
  const logMessage = req.body.message;
  winston.info(logMessage);
  res.sendStatus(201);
});

// Implement security best practices for request logging
